     1→import express from "express";
     2→import path from "path";
     3→import { createServer as createViteServer } from "vite";
     4→import { GoogleGenAI, Type } from "@google/genai";
     5→
     6→async function startServer() {
     7→  const app = express();
     8→  const PORT = Number(process.env.PORT || 5000);
     9→
    10→  app.use(express.json());
    11→
    12→  // API routes
    13→  app.post("/api/generate", async (req, res) => {
    14→    try {
    15→      const { prompt, schema, context } = req.body;
    16→      const apiKey = process.env.GEMINI_API_KEY;
    17→      
    18→      if (!apiKey) {
    19→        return res.status(500).json({ error: "API Key is missing." });
    20→      }
    21→
    22→      const ai = new GoogleGenAI({
    23→        apiKey,
    24→        httpOptions: {
    25→          headers: {
    26→            'User-Agent': 'aistudio-build',
    27→          }
    28→        }
    29→      });
    30→
    31→      let fullPrompt = prompt;
    32→      if (context) {
    33→        fullPrompt += `\n\nContext information:\n${context}`;
    34→      }
    35→
    36→      const response = await ai.models.generateContent({
    37→        model: "gemini-3.5-flash",
    38→        contents: fullPrompt,
    39→        config: {
    40→          systemInstruction: "You are an AI authoring assistant for a CRPG engine. Generate game content matching the provided schema.",
    41→          responseMimeType: "application/json",
    42→          responseSchema: schema,
    43→          temperature: 0.7,
    44→        },
    45→      });
    46→
    47→      res.json({ result: response.text });
    48→    } catch (e: any) {
    49→      console.error(e);
    50→      res.status(500).json({ error: e.message || "Failed to generate content" });
    51→    }
    52→  });
    53→
    54→  // Vite middleware for development
    55→  if (process.env.NODE_ENV !== "production") {
    56→    const vite = await createViteServer({
    57→      server: { middlewareMode: true },
    58→      appType: "spa",
    59→    });
    60→    app.use(vite.middlewares);
    61→  } else {
    62→    const distPath = path.join(process.cwd(), 'dist');
    63→    app.use(express.static(distPath));
    64→    app.get('*', (req, res) => {
    65→      res.sendFile(path.join(distPath, 'index.html'));
    66→    });
    67→  }
    68→
    69→  app.listen(PORT, "0.0.0.0", () => {
    70→    console.log(`Server running on http://localhost:${PORT}`);
    71→  });
    72→}
    73→
    74→startServer();
    75→

